    {
      "risk": "Dual-write problem: delivery status committed to DB but event publish fails, causing silent notification loss",
      "severity": "high",
      "mitigation": "Use the Transactional Outbox pattern. Write the event to an outbox table in the same DB transaction as the delivery status update. A separate relay process polls the outbox and publishes to the queue. This guarantees atomicity without distributed transactions."
    },
    {
      "risk": "Poison messages: a malformed event causes the consumer to crash repeatedly, blocking the queue",
      "severity": "medium",
      "mitigation": "Configure max retry count (e.g., 5 attempts with exponential backoff). After exhaustion, route to Dead Letter Queue. Monitor DLQ depth with alerts. Never allow infinite retries."
    },
    {
      "risk": "Duplicate notifications sent to customers due to at-least-once delivery",
      "severity": "medium",
      "mitigation": "Channel adapters must use provider-level idempotency keys (e.g., Twilio MessageSid dedup, SendGrid custom unique args). Additionally, track notificationId + channel in a sent-notifications table to short-circuit duplicates before calling the provider."
    },
    {
      "risk": "Operational complexity exceeds what 3 engineers can maintain",
      "severity": "medium",
      "mitigation": "Use a managed queue service (SQS, Cloud Tasks) or a Postgres-backed job queue (pgboss, graphile-worker) to minimize operational surface. Avoid self-hosted Kafka or RabbitMQ. The Postgres option is particularly attractive: zero new infrastructure, the team already operates Postgres."
    },
    {
      "risk": "Notification preferences and contact details become stale or inconsistent",
      "severity": "low",
      "mitigation": "Customer preferences should be owned by the Notification context and fetched at dispatch time (not cached in the event). This ensures the latest opt-outs and contact details are always used."
    }
  ],

